INSERT INTO questions (id, question, choice_a, choice_b, choice_c, choice_d, answer, explanation, genre, difficulty, era, title, created_at, source) VALUES (436, 'アメリカで大ヒットした『Power Rangers』第1作の映像の原型となった、1992年のスーパー戦隊は？', '忍者戦隊カクレンジャー', '恐竜戦隊ジュウレンジャー', '鳥人戦隊ジェットマン', '五星戦隊ダイレンジャー', 'B', '初代Power Rangersはジュウレンジャーの戦闘映像を流用して制作された。ダイレンジャーとカクレンジャーは続編に使用され、半分正しいひっかけ。', '特撮', '激むず', 1992, '恐竜戦隊ジュウレンジャー', '2026-06-11 22:55:18', 'prototype-slice/claude-sonnet-4-6');
