INSERT INTO questions (id, question, choice_a, choice_b, choice_c, choice_d, answer, explanation, genre, difficulty, era, title, created_at, source) VALUES (791, '『ドラゴンクエスト』シリーズで全作の音楽を手がけ、序曲（オープニングテーマ）も作曲した人物は誰？', 'すぎやまこういち', '植松伸夫', '近藤浩治', '光田康典', 'A', 'すぎやまこういちは『ドラゴンクエスト』シリーズ全般の音楽を手がけ、序曲は特に有名である。', 'ゲームBGM', 'ふつう', 1986, 'ドラゴンクエスト', '2026-06-25 16:06:03', 'claude-code / generator');
